import type { ToolsEquipmentDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';

export function toCreateToolsEquipmentPayload(form: Partial<ToolsEquipmentDto>) {
  return {
    code: normalizeCode(form.code ?? ''),
    name: form.name!.trim(),
    unit: form.unit!.trim(),
    accountCode: normalizeCode(form.accountCode ?? ''),
    allocationAccountCode: normalizeCode(form.allocationAccountCode ?? ''),
    allocationMonths: form.allocationMonths ?? 12,
    originalCost: form.originalCost ?? 0,
    categoryCode: form.categoryCode?.trim() || undefined,
    allocationMethod: form.allocationMethod?.trim() || 'Monthly',
  };
}

export function toUpdateToolsEquipmentPayload(form: Partial<ToolsEquipmentDto>) {
  return {
    name: form.name!.trim(),
    unit: form.unit!.trim(),
    accountCode: normalizeCode(form.accountCode ?? ''),
    allocationAccountCode: normalizeCode(form.allocationAccountCode ?? ''),
    allocationMonths: form.allocationMonths ?? 12,
    isActive: form.isActive ?? true,
    originalCost: form.originalCost ?? 0,
    categoryCode: form.categoryCode?.trim() || undefined,
    allocationMethod: form.allocationMethod?.trim() || 'Monthly',
  };
}
