import React, { useCallback, useMemo, useRef, useState } from 'react';
import {
  Input,
  Modal,
  SearchInput,
  SearchTextInput,
  Select,
  MoneyInput, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { ToolsEquipmentDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { getSharedCatalogEditBlockedMessage, catalogRowEditHintDismissStorageKey } from '../../../utils/sharedCatalogEditBlockedMessage';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { createAccountSearchConfig, formatAccountDisplay } from '../../../components/search';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { selectPlaceholderClass } from '../../../utils/selectField';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useServerPagedListLoading,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListMasterLinPageLayout,
  CatalogListHeaderFilters,
  CatalogLegacyCodeSuffix,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogCodeReplaceProvider,
  CatalogRowActionMenu,
  type CatalogRowMenuAction,
  type CatalogListToolbarBridge,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { toCreateToolsEquipmentPayload, toUpdateToolsEquipmentPayload } from './ccdcPayload';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ccdc';
const CATALOG_KIND = 'tools-equipment';

type FormErrors = Partial<
  Record<'code' | 'name' | 'unit' | 'allocationMonths' | 'accountCode' | 'allocationAccountCode', string>
>;

const CcdcPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: ToolsEquipmentDto } | null>(null);
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<ToolsEquipmentDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<ToolsEquipmentDto | null>(null);
  const initFormName = modalOpen && editing ? 'edit-tools-equipment' : 'create-tools-equipment';
  const { unitOptions } = useVoucherInitData(initFormName);
  const [form, setForm] = useState<Partial<ToolsEquipmentDto>>({ isActive: true, allocationMonths: 12 });
  const [accountName, setAccountName] = useState('');
  const [allocationAccountName, setAllocationAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService
        .getToolsEquipment({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải CCDC', type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã CCDC';
    if (!form.name?.trim()) next.name = 'Nhập tên CCDC';
    if (!form.unit?.trim()) next.unit = 'Chọn đơn vị tính';
    const months = form.allocationMonths;
    if (months == null || months < 1 || months > 120) {
      next.allocationMonths = 'Nhập số tháng phân bổ (1–120)';
    }
    if (!form.accountCode?.trim()) next.accountCode = 'Chọn TK hạch toán CCDC';
    if (!form.allocationAccountCode?.trim()) next.allocationAccountCode = 'Chọn TK phân bổ chi phí';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true, allocationMonths: 12, originalCost: 0, allocationMethod: 'Monthly' });
    setAccountName('');
    setAllocationAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: ToolsEquipmentDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setAccountName('');
    setAllocationAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [markClean]);

  const openEdit = useCallback((row: ToolsEquipmentDto) => {
    if (!canWrite || isSharedCatalogReadOnly(row)) {
      openView(row);
      return;
    }
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setAccountName('');
    setAllocationAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  }, [canWrite, markClean, openView]);

  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: ToolsEquipmentDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'renameCode':
          toolbarBridgeRef.current?.openRename();
          break;
        case 'delete': {
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        }
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuReadOnly = rowMenuRow ? isSharedCatalogReadOnly(rowMenuRow) : false;
  const rowMenuShowEdit = !!rowMenuRow && canWrite && !rowMenuReadOnly;
  const rowMenuShowView = !!rowMenuRow && (!canWrite || rowMenuReadOnly);

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateToolsEquipment(editing.id, toUpdateToolsEquipmentPayload(form));
      } else {
        await masterService.createToolsEquipment(toCreateToolsEquipmentPayload(form));
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật CCDC thành công' : 'Tạo CCDC thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateToolsEquipment(id, toUpdateToolsEquipmentPayload({ ...row, isActive: false }));
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} CCDC`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteToolsEquipment(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} CCDC`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </div>
    </CatalogListHeaderFilters>
  );

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{ title: 'Danh mục CCDC', titleIconClass: 'fas fa-toolbox' }}
        listTitle="Danh sách CCDC"
        listRowMenuHelp
        filterMaxWidthPx={1000}
        filters={filterBar}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => reloadSchema()}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={TEST_ID}
              showEdit={rowMenuShowEdit}
              showView={rowMenuShowView}
              showHistory={!!rowMenuRow}
              showRename={rowMenuShowEdit}
              showDelete={rowMenuShowEdit}
            />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy CCDC phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            getRowEditBlockedMessage={getSharedCatalogEditBlockedMessage}
            rowEditHintDismissStorageKey={catalogRowEditHintDismissStorageKey(TEST_ID)}
            onRowOpenActionMenu={handleRowOpenActionMenu}
            rowMenuHintMessage={rowMenuHintMessage}
            rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
            enableRowMenuLongPress={viewMobile}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem CCDC dùng chung' : editing ? 'Sửa CCDC' : 'Thêm CCDC'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã CCDC *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
                <CatalogLegacyCodeSuffix
                  testIdPrefix={TEST_ID}
                  code={editing?.code}
                  legacyCode={editing?.legacyCode}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên CCDC *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unit`}>
              <label className={styles.label}>Đơn vị tính *</label>
              <Select
                value={form.unit ?? ''}
                required
                disabled={viewOnlyShared}
                placeholder="— Chọn ĐVT —"
                error={errors.unit}
                className={selectPlaceholderClass(form.unit)}
                onChange={e => {
                  markDirty();
                  clearFieldError('unit');
                  setForm(f => ({ ...f, unit: normalizeCode(e.target.value) }));
                }}
                options={unitOptions}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationMonths`}>
              <label className={styles.label}>Số tháng phân bổ *</label>
              <Input
                type="number"
                min={1}
                max={120}
                value={form.allocationMonths ?? ''}
                disabled={viewOnlyShared}
                error={errors.allocationMonths}
                onChange={e => {
                  markDirty();
                  clearFieldError('allocationMonths');
                  setForm(f => ({
                    ...f,
                    allocationMonths: e.target.value ? Number(e.target.value) : undefined,
                  }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
              <label className={styles.label}>TK hạch toán CCDC *</label>
              <SearchInput
                config={accountSearchConfig}
                value={form.accountCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
                error={errors.accountCode}
                disabled={viewOnlyShared}
                onChange={a => {
                  markDirty();
                  clearFieldError('accountCode');
                  setForm(f => ({ ...f, accountCode: normalizeCode(a.code) }));
                  setAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, accountCode: undefined }));
                  setAccountName('');
                  setErrors(prev => ({ ...prev, accountCode: 'Chọn TK hạch toán CCDC' }));
                }}
                showLabel={false}
                showSecondaryInput={false}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationAccountCode`}>
              <label className={styles.label}>TK phân bổ chi phí *</label>
              <SearchInput
                config={accountSearchConfig}
                value={form.allocationAccountCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.allocationAccountCode ?? '', allocationAccountName)}
                error={errors.allocationAccountCode}
                disabled={viewOnlyShared}
                onChange={a => {
                  markDirty();
                  clearFieldError('allocationAccountCode');
                  setForm(f => ({ ...f, allocationAccountCode: normalizeCode(a.code) }));
                  setAllocationAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, allocationAccountCode: undefined }));
                  setAllocationAccountName('');
                  setErrors(prev => ({ ...prev, allocationAccountCode: 'Chọn TK phân bổ chi phí' }));
                }}
                showLabel={false}
                showSecondaryInput={false}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-originalCost`}>
              <label className={styles.label}>Nguyên giá</label>
              <MoneyInput
                value={form.originalCost ?? 0}
                disabled={viewOnlyShared}
                onChange={v => {
                  markDirty();
                  setForm(f => ({ ...f, originalCost: v }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-categoryCode`}>
              <label className={styles.label}>Mã nhóm CCDC</label>
              <Input
                value={form.categoryCode ?? ''}
                disabled={viewOnlyShared}
                className={styles.codeInput}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, categoryCode: normalizeCode(e.target.value) || undefined }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationMethod`}>
              <label className={styles.label}>Phương pháp phân bổ</label>
              <Select
                value={form.allocationMethod ?? 'Monthly'}
                disabled={viewOnlyShared}
                options={[
                  { value: 'Monthly', label: 'Phân bổ theo tháng' },
                  { value: 'OneTime', label: 'Một lần' },
                ]}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, allocationMethod: e.target.value }));
                }}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              unit: form.unit,
              allocationMonths: form.allocationMonths,
              accountCode: form.accountCode,
              allocationAccountCode: form.allocationAccountCode,
              originalCost: form.originalCost,
              categoryCode: form.categoryCode,
              allocationMethod: form.allocationMethod,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                editing={editing ? { id: editing.id, code: editing.code } : null}
              />
            </>
            }
            saveDisabled={viewOnlyShared}
          />
        </div>
      </Modal>
    </>
      </CatalogCodeReplaceProvider>
  );
};

export default CcdcPage;
